#include <stdio.h>


int main() {
  int nor ;
  scanf("%d", &nor) ;
  int rots[nor] ;
  for(int i = 0 ; i < nor ; i++) {
    scanf("%d", &rots[i]) ;
  }

  int lim = (1 << nor) ;
  // printf("%d", lim) ;
  for(int k = 0; k < lim ; k++) {
    // printf("%d",i) ;
    int i = k ;
    int sum = 0 ;
    for(int j = 0 ; j < nor ; j++) {
      // printf("%d", i % 2) ;
      if(i % 2) {
        sum += rots[j] ;
      } else {
        sum -= rots[j] ;
      }
      i = i >> 1 ;
    }
    if(sum % 360 == 0) {
      printf("YES") ;
      return 0 ;
    }
  }

  printf("NO") ;
  return 0 ;
}

