mod my {
    pub mod io {
        use std::io::{BufRead, ErrorKind};

        pub fn read_word<R: BufRead>(r: &mut R, buf: &mut Vec<u8>)
                                              -> std::io::Result<usize> {
            let mut read = 0;
            loop {
                let (done, used) = {
                    let available = match r.fill_buf() {
                        Ok(n) => n,
                        Err(ref e) if e.kind() == ErrorKind::Interrupted => continue,
                        Err(e) => return Err(e)
                    };
                    match available.iter().position(|&x| x == b'\n' || x == b' ') {
                        Some(i) => {
                            buf.extend_from_slice(&available[..i]);
                            (true, i + 1)
                        }
                        None => {
                            buf.extend_from_slice(available);
                            (false, available.len())
                        }
                    }
                };
                r.consume(used);
                read += used;
                if done || used == 0 {
                    return Ok(read);
                }
            }
        }

        pub struct InputReader<R: BufRead> {
            reader: R,
            buf: Vec<u8>,
        }

        impl<R: BufRead> InputReader<R> {
            pub fn new(reader: R) -> Self {
                Self {
                    reader,
                    buf: Vec::<u8>::new(),
                }
            }

            pub fn read_word(&mut self) {
                read_word(&mut self.reader, &mut self.buf);
            }

            pub fn read<T>(&mut self) -> T
                where T: std::str::FromStr,
                      T::Err: std::fmt::Debug
            {
                self.buf.clear();
                self.read_word();
                std::str::from_utf8(&self.buf).unwrap().trim().parse().unwrap()
            }
        }
    }
}

fn main() {
    let stdin = std::io::stdin();
    let mut stdin = my::io::InputReader::new(stdin.lock());

    let n: usize = stdin.read();
    let mut a = Vec::<i32>::new();

    for i in 0..n {
        a.push(stdin.read());
    }
    let mut result = false;
    for bit in 0..(1 << n) {
        let mut sum = 0;
        for i in 0..n {
            if bit & (1 << i) > 0 {
                sum += a[i];
            } else {
                sum -= a[i];
            }
        }
        if sum.abs() % 360 == 0 {
            result = true;
            break;
        }
    }
    println!("{}", if result { "YES" } else { "NO" });
}
